// Normalize scraped jobs.
const results = [];

for (const item of $input.all()) {
  const j = item.json;

  const url         = (j.jobUrl || j.url || j.link || '').trim();
  const title       = j.title || j.jobTitle || j.position || '';
  const company     = j.company || j.companyName || '';
  const location    = j.location || j.jobLocation || '';
  const description = j.description || j.jobDescription || j.descriptionHtml || '';

  if (!url || !title || !description || description.length < 100) {
    continue;
  }

  results.push({
    json: {
      url,
      title,
      company,
      location,
      description
    }
  });
}

console.log(`Jobs after normalization: ${results.length}`);
return results;

// Regex-only relocation + sponsorship filter.
const results = [];

const HIGH_PATTERNS = [
  /visa sponsorship/i,
  /sponsorship available/i,
  /provide visa/i,
  /work permit sponsorship/i,
  /relocation support/i,
  /relocation package/i,
  /kennismigrant/i,
  /ind sponsor/i,
  /visa sponsor/i,
  /sponsoring visas/i,
  /we sponsor/i,
  /sponsor your visa/i,
  /global mobility/i
];

const MEDIUM_PATTERNS = [
  /eu blue card/i,
  /highly skilled migrant/i,
  /work authorization/i,
  /must be eligible to work/i,
  /relocate to netherlands/i,
  /immigration support/i,
  /work permit/i
];

for (const item of $input.all()) {
  const job = item.json;

  const text = `${job.title}\n${job.description}`.toLowerCase();

  const matchedHigh = HIGH_PATTERNS
    .filter(r => r.test(text))
    .map(r => r.source.replace(/\\/g, ''));

  const matchedMedium = MEDIUM_PATTERNS
    .filter(r => r.test(text))
    .map(r => r.source.replace(/\\/g, ''));

  if (matchedHigh.length === 0 && matchedMedium.length === 0) {
    continue;
  }

  const confidence = matchedHigh.length > 0 ? 'high' : 'medium';

  results.push({
    json: {
      url: job.url,
      title: job.title,
      company: job.company,
      location: job.location,
      description: job.description,
      relocation_signals: [...matchedHigh, ...matchedMedium].join(', '),
      relocation_confidence: confidence
    }
  });
}

console.log(`Jobs after regex relocation filter: ${results.length}`);
return results;

// Build cover letter LLM request using wf1-style prompting.
const items = $input.all();
const results = [];

for (const item of items) {
  const {
    url,
    title,
    company,
    location,
    description,
    relocation_signals,
    relocation_confidence
  } = item.json;

  const payload = {
    model: 'unsloth/Qwen3.5-9B-GGUF:Q6_K',
    temperature: 0.7,
    max_tokens: 12000,
    messages: [
      {
        role: 'system',
        content: 'Write an optimized cover letter for the incoming job description. Use only information from the provided resume. Do not make anything up. The cover letter should be one paragraph followed by bullet points. Output plain text only. No markdown fences. No reasoning. No thinking.'
      },
      {
        role: 'user',
        content: `Job Description:\n${description.slice(0, 3000)}\n\nResume:\nShirsak Sahoo\nSenior Software Engineer (SDE3/AVP) with 6+ years experience. Currently at JPMorgan Chase Asset & Wealth Management building AI-native platforms including Connect Studio, MCP server infrastructure, RAG pipelines and internal AI tooling. Strong experience in React, TypeScript, JavaScript, Python, AWS, Node.js, GraphQL and agentic AI systems. BITS Pilani Computer Science graduate (2019). Experience building scalable frontend systems, full-stack platforms, developer tooling, AI workflows and automation systems. Looking to relocate to the Netherlands through the kennismigrant visa pathway. Available for remote interviews and relocation in Q3/Q4 2026.\n\nCompany: ${company}\nRole: ${title}\nLocation: ${location}`
      }
    ],
    extra_body: {
      chat_template_kwargs: {
        enable_thinking: false
      }
    }
  };

  results.push({
    json: {
      _job: {
        url,
        title,
        company,
        location,
        description,
        relocation_signals,
        relocation_confidence
      },
      _llmPayload: payload
    }
  });
}

return results;

// Assemble final sheet row.
const llmItems = $input.all();
const reqItems = $('Build Cover Letter Request').all();
const results = [];

for (let i = 0; i < llmItems.length; i++) {
  try {
    const llmItem = llmItems[i];
    const reqItem = reqItems[i];

    if (!llmItem?.json || !reqItem?.json?._job) continue;

    const coverLetter = (llmItem.json?.choices?.[0]?.message?.content || '').trim();

    if (!coverLetter) continue;

    const job = reqItem.json._job;

    results.push({
      json: {
        date: new Date().toISOString().split('T')[0],
        company: job.company || '',
        title: job.title || '',
        location: job.location || '',
        url: job.url || '',
        relocation_signals: job.relocation_signals || '',
        relocation_confidence: job.relocation_confidence || '',
        cover_letter: coverLetter,
        status: 'Not Applied'
      }
    });
  } catch (e) {
    console.log('Assemble error:', e.message);
  }
}

return results;
